#include <stdio.h>
#include <string.h>

int countDisliked(int L, int R, int a[]) {
    int count = 0;
    for (int i = L; i <= R; i++) {
        int digits[10] = {0};
        int num = i;
        while (num > 0) {
            digits[num % 10]++;
            num /= 10;
        }
        int disliked = 0;
        for (int j = 0; j < 10; j++) {
            if (digits[j] == a[j]) {
                disliked = 1;
                break;
            }
        }
        if (disliked) count++;
    }
    return count;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int L, R;
        scanf("%d %d", &L, &R);
        int a[10];
        for (int i = 0; i < 10; i++) {
            scanf("%d", &a[i]);
        }
        int count = countDisliked(L, R, a);
        printf("%d\n", R - L + 1 - count);
    }
    return 0;
}

