import java.util.Scanner;

public class Main {
    public static int countDisliked(long L, long R, int[] a) {
        int count = 0;
        for (long i = L; i <= R; i++) {
            int[] digits = new int[10];
            long num = i;
            while (num > 0) {
                digits[(int) (num % 10)]++;
                num /= 10;
            }
            int disliked = 0;
            for (int j = 0; j < 10; j++) {
                if (digits[j] == a[j]) {
                    disliked = 1;
                    break;
                }
            }
            if (disliked) count++;
        }
        return count;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long L = sc.nextLong();
            long R = sc.nextLong();
            int[] a = new int[10];
            for (int i = 0; i < 10; i++) {
                a[i] = sc.nextInt();
            }
            int count = countDisliked(L, R, a);
            System.out.println(R - L + 1 - count);
        }
    }
}

